{"path": "/tmp/sv-1ef5b2b673fc4bc891ef75ddc1f3c3a1/Components/Catalog/ProductCard.razor", "file_text": "
<div class="product-card" @onclick="HandleCardClick">
    <div class="product-image" role="img" aria-label="@Product.Name">
        <span>@Product.Name</span>
    </div>
    <div class="product-info">
        <h3 class="product-name">@Product.Name</h3>
        <p class="product-price">@Product.Price.ToString("C")</p>
        <div class="product-rating" aria-label="@($"Rating: {RoundedRating} out of 5")">
            @for (int i = 1; i <= 5; i++)
            {
                @(i <= RoundedRating ? "★" : "☆")
            }
        </div>
        @if (!Product.InStock)
        {
            <span class="out-of-stock-badge">Out of Stock</span>
        }
        <button class="add-to-cart-btn"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<int> OnSelected { get; set; }

    [Parameter]
    public EventCallback<int> OnAddToCart { get; set; }

    private int RoundedRating => (int)Math.Round(Product.Rating);

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product.Id);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product.Id);
        }
    }
}
"}

