{"path": "/tmp/sv-1ef5b2b673fc4bc891ef75ddc1f3c3a1/Components/Catalog/CatalogPagination.razor", "file_text": "
@if (TotalPages > 1)
{
    <nav class="catalog-pagination" aria-label="Product catalog pagination">
        <button class="page-btn"
                disabled="@(CurrentPage <= 1)"
                @onclick="@(() => OnPageChanged.InvokeAsync(CurrentPage - 1))">
            Previous
        </button>

        @foreach (var page in PageNumbers)
        {
            <button class="page-btn @(page == CurrentPage ? "active" : "")"
                    @onclick="@(() => OnPageChanged.InvokeAsync(page))">
                @page
            </button>
        }

        <button class="page-btn"
                disabled="@(CurrentPage >= TotalPages)"
                @onclick="@(() => OnPageChanged.InvokeAsync(CurrentPage + 1))">
            Next
        </button>
    </nav>
}

@code {
    [Parameter]
    public int CurrentPage { get; set; } = 1;

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private IEnumerable<int> PageNumbers
    {
        get
        {
            // Show up to 7 pages centered around the current page
            int start = Math.Max(1, CurrentPage - 3);
            int end = Math.Min(TotalPages, start + 6);
            start = Math.Max(1, end - 6);

            for (int i = start; i <= end; i++)
                yield return i;
        }
    }
}
"}

