arguments.file_text:
@page "/catalog"
@using sv_1ef5b2b673fc4bc891ef75ddc1f3c3a1.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div class="catalog-error">
        <p>Something went wrong: @_error</p>
        <button @onclick="RetryAsync">Try Again</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <div class="catalog-sidebar">
            <CatalogFilters Categories="_categories"
                            OnFilterApplied="HandleFilterApplied"
                            OnFilterCleared="HandleFilterCleared" />
        </div>

        <div class="catalog-main">
            @if (_loading)
            {
                <div class="catalog-loading">Loading products…</div>
            }
            else if (_result is null || _result.Items.Count == 0)
            {
                <div class="catalog-empty">
                    <p>No products found matching your criteria.</p>
                </div>
            }
            else
            {
                <CatalogToolbar SortBy="@_sortBy"
                                FirstItem="_firstItem"
                                LastItem="_lastItem"
                                TotalCount="_result.TotalCount"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_currentPage"
                                   TotalPages="_totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </div>
    </div>
}

@code {
    /// <summary>Raised when a product card is clicked, passing the product ID for navigation.</summary>
    [Parameter]
    public EventCallback<int> OnProductSelected { get; set; }

    private List<string> _categories = [];
    private PagedResult<Product>? _result;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 12;
    private bool _loading = true;
    private string? _error;

    private int _totalPages => _result is null || _result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / PageSize);

    private int _firstItem => _result is null || _result.Items.Count == 0
        ? 0
        : (_currentPage - 1) * PageSize + 1;

    private int _lastItem => _result is null
        ? 0
        : (_currentPage - 1) * PageSize + _result.Items.Count;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            // Load categories and products in parallel on first load
            if (_categories.Count == 0)
            {
                var categoriesTask = ProductService.GetCategoriesAsync();
                var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
                await Task.WhenAll(categoriesTask, productsTask);

                _categories = await categoriesTask;
                _result = await productsTask;
            }
            else
            {
                _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
            }
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string? sortBy)
    {
        _sortBy = sortBy ?? "price_asc";
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadDataAsync();
    }

    private async Task HandleProductSelected(int productId)
    {
        await OnProductSelected.InvokeAsync(productId);
    }

    private async Task HandleAddToCart(int productId)
    {
        // Placeholder for cart functionality
        await Task.CompletedTask;
    }

    private async Task RetryAsync()
    {
        await LoadDataAsync();
    }
}

.catalog-layout {
    display: flex;
    gap: 2rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-loading,
.catalog-empty,
.catalog-error {
    text-align: center;
    padding: 3rem 1rem;
    color: #666;
    font-size: 1.05rem;
}

.catalog-error {
    color: #c0392b;
    background: #fdf0ef;
    border: 1px solid #e6b0aa;
    border-radius: 8px;
}

.catalog-error button {
    margin-top: 0.75rem;
