    color: #c0392b;
    background: #fdf0ef;
    border: 1px solid #e6b0aa;
    border-radius: 8px;
}

.catalog-error button {
    margin-top: 0.75rem;
    padding: 0.5rem 1.25rem;
    border: none;
    border-radius: 4px;
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
}

.catalog-error button:hover {
    background: #0a58ca;
}

